  const key = encodeRelayConnectionTarget(target);
  const existing = relaySubscribers.get(key);
  if (existing) {
    return existing;
  }

  const subscription = new RelayLiveSubscription(target);
  relaySubscribers.set(key, subscription);
  return subscription;
}

